cat > binlog-parser/Program.cs << 'CEOF'
using System;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = Serialization.Read(binlogPath);

Console.WriteLine("=== BUILD RESULT ===");
Console.WriteLine($"Succeeded: {build.Succeeded}");
Console.WriteLine();

// Collect all errors
Console.WriteLine("=== ALL ERRORS ===");
var errors = build.FindChildrenRecursive<Error>().ToList();
foreach (var e in errors)
{
    var project = GetParentProject(e);
    Console.WriteLine($"[{project}] {e.Code}: {e.Text}");
    if (!string.IsNullOrEmpty(e.File))
        Console.WriteLine($"  File: {e.File}({e.LineNumber},{e.ColumnNumber})");
    Console.WriteLine();
}

Console.WriteLine($"Total errors: {errors.Count}");
Console.WriteLine();

// Collect all warnings
Console.WriteLine("=== WARNINGS (first 30) ===");
var warnings = build.FindChildrenRecursive<Warning>().ToList();
foreach (var w in warnings.Take(30))
{
    var project = GetParentProject(w);
    Console.WriteLine($"[{project}] {w.Code}: {w.Text}");
}
Console.WriteLine($"Total warnings: {warnings.Count}");
Console.WriteLine();

// Project summary
Console.WriteLine("=== PROJECT BUILD SUMMARY ===");
var projects = build.FindChildrenRecursive<Project>().ToList();
foreach (var p in projects)
{
    var projErrors = p.FindChildrenRecursive<Error>().ToList();
    var projWarnings = p.FindChildrenRecursive<Warning>().ToList();
    if (projErrors.Count > 0 || projWarnings.Count > 0)
    {
        Console.WriteLine($"Project: {p.Name} | Errors: {projErrors.Count} | Warnings: {projWarnings.Count}");
        foreach (var e in projErrors)
            Console.WriteLine($"  ERROR {e.Code}: {e.Text}");
    }
}

static string GetParentProject(BaseNode node)
{
    var current = node.Parent;
    while (current != null)
    {
        if (current is Project p) return p.Name;
        current = current.Parent;
    }
    return "(unknown)";
}
