using System;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = Serialization.Read(binlogPath);

// Extract all source files from the build
Console.WriteLine("=== EMBEDDED SOURCE FILES ===");
var sourceFiles = build.FindChildrenRecursive<SourceFile>().ToList();
foreach (var sf in sourceFiles)
{
    Console.WriteLine($"  {sf.Name}");
}

Console.WriteLine();

// Extract project dependency info
Console.WriteLine("=== PROJECT TARGETS & REFERENCES ===");
var projects = build.FindChildrenRecursive<Project>().ToList();
foreach (var p in projects)
{
    Console.WriteLine($"\nProject: {p.Name} (targets: {p.TargetFramework})");

    // Look for PackageReference items
    var addItems = p.FindChildrenRecursive<AddItem>().ToList();
    foreach (var ai in addItems)
    {
        if (ai.Name == "PackageReference" || ai.Name == "ProjectReference" || ai.Name == "Reference")
        {
            Console.WriteLine($"  [{ai.Name}]");
            foreach (var child in ai.Children)
                Console.WriteLine($"    {child}");
        }
    }

    // Look for tasks related to ResolveAssemblyReference
    var tasks = p.FindChildrenRecursive<Task>().Where(t => t.Name == "ResolvePackageAssets" || t.Name == "ResolveAssemblyReference").ToList();
    foreach (var t in tasks)
    {
        if (t.FindChildrenRecursive<Error>().Any() || t.FindChildrenRecursive<Warning>().Any())
        {
            Console.WriteLine($"  Task {t.Name} had issues");
        }
    }
}

// Try to get source file content
Console.WriteLine("\n=== LOOKING FOR SOURCE FILE CONTENT ===");
var allNodes = build.FindChildrenRecursive<BaseNode>().ToList();
Console.WriteLine($"Total nodes: {allNodes.Count}");

// Search for file content or Csc task input
var cscTasks = build.FindChildrenRecursive<Task>().Where(t => t.Name == "Csc").ToList();
foreach (var csc in cscTasks)
{
    Console.WriteLine($"\nCsc task in {GetParentProject(csc)}:");
    var parameters = csc.FindChildrenRecursive<Parameter>().ToList();
    foreach (var param in parameters)
    {
        if (param.Name == "Sources" || param.Name == "References")
        {
            Console.WriteLine($"  {param.Name}:");
            foreach (var child in param.Children.Take(50))
                Console.WriteLine($"    {child}");
        }
    }
}

static string GetParentProject(BaseNode node)
{
    var current = node.Parent;
    while (current != null)
    {
        if (current is Project p) return p.Name;
        current = current.Parent;
    }
    return "(unknown)";
}
