using System;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = Serialization.Read(binlogPath);

// Get all errors with full context
Console.WriteLine("=== ALL ERRORS WITH CONTEXT ===");
var errors = build.FindChildrenRecursive<Error>().ToList();
foreach (var e in errors)
{
    Console.WriteLine($"Code: {e.Code}");
    Console.WriteLine($"Text: {e.Text}");
    Console.WriteLine($"File: {e.File}");
    Console.WriteLine($"Line: {e.LineNumber}, Col: {e.ColumnNumber}");
    Console.WriteLine($"Project: {e.ProjectFile}");
    Console.WriteLine($"Subcategory: {e.Subcategory}");
    Console.WriteLine($"SenderName: {e.SenderName}");

    // Walk up hierarchy
    var current = e.Parent;
    var path = "";
    while (current != null)
    {
        path += $" -> {current.GetType().Name}({current})";
        current = current.Parent;
    }
    Console.WriteLine($"Hierarchy: {path}");
    Console.WriteLine("---");
}

// Check project.assets.json for Services to see if Newtonsoft.Json is referenced
Console.WriteLine("\n=== SERVICES project.assets.json (libraries section) ===");
var assetsPath = "Services/obj/project.assets.json";
var allMessages = build.FindChildrenRecursive<Message>().ToList();
var nugetMessages = allMessages.Where(m => m.Text != null && 
    (m.Text.Contains("Newtonsoft") || m.Text.Contains("package") && m.Text.Contains("Services")))
    .ToList();
foreach (var m in nugetMessages.Take(20))
{
    Console.WriteLine($"  {m.Text}");
}

// Look for restore info
Console.WriteLine("\n=== RESTORE MESSAGES ===");
var restoreMsgs = allMessages.Where(m => m.Text != null && m.Text.Contains("Restore")).Take(10).ToList();
foreach (var m in restoreMsgs)
{
    Console.WriteLine($"  {m.Text}");
}

// Check for dependent project failures
Console.WriteLine("\n=== PROJECT BUILD ORDER AND FAILURE CASCADE ===");
var projects = build.FindChildrenRecursive<Project>().ToList();
foreach (var p in projects)
{
    var errs = p.FindChildrenRecursive<Error>().ToList();
    var succeeded = !errs.Any();

    // Check for "project reference not built" messages
    var notBuiltMsgs = p.FindChildrenRecursive<Message>()
        .Where(m => m.Text != null && (m.Text.Contains("not build") || m.Text.Contains("dependency")))
        .ToList();

    if (errs.Any() || notBuiltMsgs.Any())
    {
        Console.WriteLine($"\nProject: {p.Name} - {(succeeded ? "SUCCEEDED" : "FAILED")}");
        foreach (var e in errs)
            Console.WriteLine($"  ERROR: {e.Code} - {e.Text}");
        foreach (var m in notBuiltMsgs)
            Console.WriteLine($"  MSG: {m.Text}");
    }
}

// Check if Api project has any build errors or was skipped
Console.WriteLine("\n=== API PROJECT STATUS ===");
var apiProjects = projects.Where(p => p.Name.Contains("Api")).ToList();
foreach (var p in apiProjects)
{
    Console.WriteLine($"Project: {p.Name}, Succeeded: {p.Succeeded}");
    var allErrs = p.FindChildrenRecursive<Error>().ToList();
